const { Client } = require('@elastic/elasticsearch');
const Joi = require('joi');

// Initialize Elasticsearch client with safeguards
const esClient = new Client({
  node: process.env.ELASTICSEARCH_URL,
  requestTimeout: 30000, // 30 second timeout
  maxRetries: 3,
  compression: 'gzip'
});

// Query complexity budget
const QUERY_LIMITS = {
  MAX_WILDCARD_LENGTH: 3,      // Min chars before wildcard
  MAX_AGGREGATION_DEPTH: 3,    // Max nested aggregations
  MAX_RESULT_SIZE: 10000,      // Max result window
  MAX_BUCKET_COUNT: 1000,      // Max aggregation buckets
  FORBIDDEN_PATTERNS: [
    /^\*.*$/,                   // Leading wildcards
    /\.\*.*\*.*\*/,             // Multiple wildcards
    /script_fields/i,           // Script field execution
    /painless/i                 // Painless scripting
  ]
};

// Query validation schema
const searchQuerySchema = Joi.object({
  index: Joi.string().required(),
  query: Joi.object().required(),
  size: Joi.number().max(QUERY_LIMITS.MAX_RESULT_SIZE).default(10),
  from: Joi.number().max(QUERY_LIMITS.MAX_RESULT_SIZE).default(0),
  aggs: Joi.object().optional(),
  sort: Joi.array().max(5).optional(),
  _source: Joi.alternatives().try(Joi.boolean(), Joi.array(), Joi.object()).optional()
});

/**
 * Validates query complexity and dangerous patterns
 */
function validateQuerySafety(queryBody) {
  const errors = [];
  const queryStr = JSON.stringify(queryBody);

  // Check for forbidden patterns
  for (const pattern of QUERY_LIMITS.FORBIDDEN_PATTERNS) {
    if (pattern.test(queryStr)) {
      errors.push(`Forbidden pattern detected: ${pattern}`);
    }
  }

  // Validate wildcard queries
  const wildcardMatches = queryStr.match(/"wildcard"\s*:\s*\{[^}]*"\*[^"]*"/g);
  if (wildcardMatches) {
    for (const match of wildcardMatches) {
      const beforeWildcard = match.split('*')[0].split('"').pop();
      if (beforeWildcard.length < QUERY_LIMITS.MAX_WILDCARD_LENGTH) {
        errors.push(`Wildcard query requires minimum ${QUERY_LIMITS.MAX_WILDCARD_LENGTH} characters prefix`);
      }
    }
  }

  // Validate aggregation depth
  if (queryBody.aggs) {
    const aggDepth = calculateAggregationDepth(queryBody.aggs);
    if (aggDepth > QUERY_LIMITS.MAX_AGGREGATION_DEPTH) {
      errors.push(`Aggregation depth ${aggDepth} exceeds limit ${QUERY_LIMITS.MAX_AGGREGATION_DEPTH}`);
    }
  }

  // Validate result window
  const resultWindow = (queryBody.from || 0) + (queryBody.size || 10);
  if (resultWindow > QUERY_LIMITS.MAX_RESULT_SIZE) {
    errors.push(`Result window ${resultWindow} exceeds maximum ${QUERY_LIMITS.MAX_RESULT_SIZE}`);
  }

  return errors;
}

/**
 * Calculates aggregation nesting depth
 */
function calculateAggregationDepth(aggs, depth = 1) {
  let maxDepth = depth;
  for (const key in aggs) {
    if (aggs[key].aggs) {
      const nestedDepth = calculateAggregationDepth(aggs[key].aggs, depth + 1);
      maxDepth = Math.max(maxDepth, nestedDepth);
    }
  }
  return maxDepth;
}

/**
 * Safe search wrapper with validation
 */
async function safeSearch(queryBody) {
  // Validate schema
  const { error, value } = searchQuerySchema.validate(queryBody);
  if (error) {
    throw new Error(`Query validation failed: ${error.message}`);
  }

  // Validate safety
  const safetyErrors = validateQuerySafety(value);
  if (safetyErrors.length > 0) {
    throw new Error(`Unsafe query detected: ${safetyErrors.join(', ')}`);
  }

  try {
    // Execute with timeout and error handling
    const response = await esClient.search({
      index: value.index,
      body: {
        query: value.query,
        aggs: value.aggs,
        size: value.size,
        from: value.from,
        sort: value.sort,
        _source: value._source,
        timeout: '30s',
        track_total_hits: 10000 // Prevent expensive count operations
      }
    });

    return response;
  } catch (err) {
    if (err.meta?.body?.error?.type === 'circuit_breaking_exception') {
      throw new Error('Query exceeded resource limits. Please refine your search.');
    }
    if (err.meta?.statusCode === 408 || err.name === 'TimeoutError') {
      throw new Error('Query timeout. Please use more specific filters.');
    }
    throw err;
  }
}

// Express.js route handler example
app.post('/api/search', async (req, res) => {
  try {
    const results = await safeSearch({
      index: 'products',
      query: req.body.query,
      size: req.body.size,
      from: req.body.from,
      aggs: req.body.aggs
    });

    res.json({
      hits: results.hits.hits,
      total: results.hits.total,
      aggregations: results.aggregations
    });
  } catch (error) {
    console.error('Search error:', error.message);
    res.status(400).json({ error: error.message });
  }
});

module.exports = { safeSearch, validateQuerySafety };

const rateLimit = require('express-rate-limit');
const RedisStore = require('rate-limit-redis');
const Redis = require('ioredis');

// Initialize Redis client
const redisClient = new Redis({
  host: process.env.REDIS_HOST,
  port: 6379,
  password: process.env.REDIS_PASSWORD,
  enableOfflineQueue: false,
  maxRetriesPerRequest: 3
});

// Global API rate limiter
const globalLimiter = rateLimit({
  store: new RedisStore({
    client: redisClient,
    prefix: 'rl:global:',
  }),
  windowMs: 60 * 1000, // 1 minute
  max: 100, // 100 requests per minute per IP
  standardHeaders: true,
  legacyHeaders: false,
  message: 'Too many requests from this IP, please try again later.',
  handler: (req, res) => {
    res.status(429).json({
      error: 'Rate limit exceeded',
      retryAfter: req.rateLimit.resetTime
    });
  }
});

// Elasticsearch search endpoint rate limiter (stricter)
const searchLimiter = rateLimit({
  store: new RedisStore({
    client: redisClient,
    prefix: 'rl:search:',
  }),
  windowMs: 60 * 1000, // 1 minute
  max: 20, // 20 search requests per minute per IP
  skipSuccessfulRequests: false,
  skipFailedRequests: true, // Don't count failed requests
  keyGenerator: (req) => {
    // Rate limit by authenticated user if available, otherwise IP
    return req.user?.id || req.ip;
  },
  handler: (req, res) => {
    console.warn(`Rate limit exceeded for ${req.ip} on search endpoint`);
    res.status(429).json({
      error: 'Search rate limit exceeded',
      limit: 20,
      windowMs: 60000,
      retryAfter: Math.ceil((req.rateLimit.resetTime - Date.now()) / 1000)
    });
  }
});

// Aggregation endpoint rate limiter (most strict)
const aggregationLimiter = rateLimit({
  store: new RedisStore({
    client: redisClient,
    prefix: 'rl:agg:',
  }),
  windowMs: 5 * 60 * 1000, // 5 minutes
  max: 10, // 10 aggregation queries per 5 minutes
  skipSuccessfulRequests: false,
  keyGenerator: (req) => req.user?.id || req.ip,
  handler: (req, res) => {
    console.error(`Aggregation rate limit exceeded for ${req.ip}`);
    res.status(429).json({
      error: 'Aggregation queries are rate limited. Please reduce query frequency.',
      limit: 10,
      windowMs: 300000
    });
  }
});

// Apply rate limiters to routes
app.use('/api', globalLimiter);
app.post('/api/search', searchLimiter, async (req, res) => { /* ... */ });
app.post('/api/search/aggregate', aggregationLimiter, async (req, res) => { /* ... */ });

// Azure API Management Policy (Optional - Infrastructure Layer)
const azureApimPolicy = `
<!--
  Azure API Management Rate Limit Policy
  Apply to Elasticsearch backend API
-->
<policies>
  <inbound>
    <!-- Rate limit by subscription key -->
    <rate-limit calls="100" renewal-period="60" />

    <!-- Rate limit by IP address -->
    <rate-limit-by-key calls="50" 
                        renewal-period="60" 
                        counter-key="@(context.Request.IpAddress)" />

    <!-- Concurrent request limit -->
    <limit-concurrency key="@(context.Request.IpAddress)" max-count="5">
      <forward-request timeout="30" />
    </limit-concurrency>

    <!-- Validate query complexity -->
    <validate-content unspecified-content-type-action="prevent" 
                     max-size="102400" 
                     errors-variable-name="validationErrors" />
  </inbound>

  <backend>
    <forward-request timeout="30" />
  </backend>

  <outbound>
    <set-header name="X-RateLimit-Limit" exists-action="override">
      <value>100</value>
    </set-header>
    <set-header name="X-RateLimit-Remaining" exists-action="override">
      <value>@(context.Response.Headers.GetValueOrDefault("X-Rate-Limit-Remaining", "0"))</value>
    </set-header>
  </outbound>

  <on-error>
    <return-response>
      <set-status code="429" reason="Too Many Requests" />
      <set-body>Rate limit exceeded. Please retry after 60 seconds.</set-body>
    </return-response>
  </on-error>
</policies>
`;

module.exports = { globalLimiter, searchLimiter, aggregationLimiter };

