# Azure Monitor KQL Alert Query
# Alert on circuit breaker exceptions
let timeWindow = 5m;
AzureDiagnostics
| where TimeGenerated > ago(timeWindow)
| where Category == "ElasticsearchSlowLogs" or Category == "ElasticsearchLogs"
| where Message contains "circuit_breaking_exception"
| summarize CircuitBreakerCount = count() by bin(TimeGenerated, 1m), NodeName = Computer
| where CircuitBreakerCount > 10  // More than 10 circuit breaker trips per minute
| project TimeGenerated, NodeName, CircuitBreakerCount

---
# Azure Monitor Alert Rule (ARM Template)
{
  "type": "Microsoft.Insights/scheduledQueryRules",
  "apiVersion": "2021-08-01",
  "name": "elasticsearch-circuit-breaker-alert",
  "location": "[resourceGroup().location]",
  "properties": {
    "displayName": "Elasticsearch Circuit Breaker DoS Alert",
    "description": "Triggers when circuit breaker exceptions exceed threshold",
    "severity": 2,
    "enabled": true,
    "evaluationFrequency": "PT5M",
    "windowSize": "PT5M",
    "criteria": {
      "allOf": [
        {
          "query": "AzureDiagnostics | where Category == 'ElasticsearchLogs' and Message contains 'circuit_breaking_exception' | summarize count() by bin(TimeGenerated, 1m)",
          "timeAggregation": "Total",
          "operator": "GreaterThan",
          "threshold": 10
        }
      ]
    },
    "actions": {
      "actionGroups": [
        "[resourceId('Microsoft.Insights/actionGroups', 'elasticsearch-oncall')]"
      ]
    }
  }
}

---
# Elasticsearch Watcher Alert (Native)
PUT _watcher/watch/heap_pressure_alert
{
  "trigger": {
    "schedule": {
      "interval": "1m"
    }
  },
  "input": {
    "http": {
      "request": {
        "host": "localhost",
        "port": 9200,
        "path": "/_nodes/stats/jvm"
      }
    }
  },
  "condition": {
    "script": {
      "source": "ctx.payload.nodes.values().stream().anyMatch(node -> node.jvm.mem.heap_used_percent > 85)"
    }
  },
  "actions": {
    "send_alert": {
      "webhook": {
        "method": "POST",
        "url": "https://hooks.slack.com/services/YOUR/WEBHOOK/URL",
        "body": "{\"text\": \"WARNING: Elasticsearch heap usage > 85%. Potential DoS attack detected.\"}"
      }
    },
    "cancel_long_running_searches": {
      "webhook": {
        "method": "POST",
        "url": "http://localhost:9200/_tasks/_cancel?actions=*search&wait_for_completion=false",
        "headers": {
          "Content-Type": "application/json"
        }
      }
    }
  }
}

