# Index slow logs for analysis
GET /elasticsearch-slowlog-*/_search
{
  "query": {
    "bool": {
      "must": [
        {
          "range": {
            "@timestamp": {
              "gte": "now-15m"
            }
          }
        },
        {
          "range": {
            "took_millis": {
              "gte": 5000
            }
          }
        }
      ],
      "should": [
        { "match": { "query_type": "wildcard" } },
        { "match": { "query_type": "aggregation" } },
        { "match": { "message": "regex" } }
      ],
      "minimum_should_match": 1
    }
  },
  "aggs": {
    "slow_query_sources": {
      "terms": {
        "field": "source.ip.keyword",
        "size": 10
      },
      "aggs": {
        "avg_duration": {
          "avg": {
            "field": "took_millis"
          }
        }
      }
    }
  }
}
